	"github.com/pocketbase/pocketbase/tools/hook"
	"github.com/pocketbase/pocketbase/tools/mailer"
)

func main() {
	app := pocketbase.New()

	// -----------------------------------------------------------------------
	// Auto-migration support (creates tables if they don't exist)
	// -----------------------------------------------------------------------
	migratecmd.MustRegister(app, app.RootCmd, migratecmd.Config{
		Automigrate: true,
	})

	// -----------------------------------------------------------------------
	// SMTP configuration for Mailpit on localhost:1025
	// -----------------------------------------------------------------------
	app.Settings().SMTP.Enabled = true
	app.Settings().SMTP.Host = "localhost"
	app.Settings().SMTP.Port = 1025
	app.Settings().SMTP.TLS = false
	app.Settings().SMTP.AuthMethod = mailer.SMTPAuthPlain
	app.Settings().SMTP.Username = ""
	app.Settings().SMTP.Password = ""

	app.Settings().Meta.SenderName = "Acme Support"
	app.Settings().Meta.SenderAddress = "noreply@acme.com"

	// -----------------------------------------------------------------------
	// OnBootstrap: seed the test user if not already present
	// -----------------------------------------------------------------------
	app.OnBootstrap().BindFunc(func(e *core.BootstrapEvent) error {
		// Persist SMTP settings
		if err := e.App.Save(e.App.Settings()); err != nil {
			e.App.Logger().Error("Failed to save SMTP settings", "error", err)
		}

		// Seed the test user
		seedTestUser(e.App)

		return e.Next()
	})

	// -----------------------------------------------------------------------
	// Mailer hook: override password reset email subject and body
	// -----------------------------------------------------------------------
	app.OnMailerRecordPasswordResetSend().Bind(&hook.Handler[*core.MailerRecordEvent]{
		Id:       "custom-password-reset",
		Priority: -1, // run before the default send handler
		Func: func(e *core.MailerRecordEvent) error {
			// Extract the JWT token from Meta
			token, ok := e.Meta["token"].(string)
			if !ok {
				e.App.Logger().Error("Missing token in password reset mailer event Meta")
				return e.Next()
			}

			// Build the custom reset link
			resetLink := "https://acme.com/reset?token=" + token

			// Determine the user's display name
			name := e.Record.GetString("name")
			if strings.TrimSpace(name) == "" {
				name = e.Record.Email()
			}

			// Build the custom HTML body
			htmlBody := fmt.Sprintf("Hi %s! Use this link: %s", name, resetLink)

			// Override the message
			e.Message.Subject = "Reset your acme.com password"
			e.Message.HTML = htmlBody

			return e.Next()
		},
	})

	// -----------------------------------------------------------------------
	// Start the server
	// -----------------------------------------------------------------------
	if err := app.Start(); err != nil {
		log.Fatal(err)
	}
}

// seedTestUser creates the verified test user if it doesn't already exist.
func seedTestUser(app core.App) {
	email := os.Getenv("TEST_USER_EMAIL")
	if email == "" {
		email = "alice@example.com"
	}
	name := os.Getenv("TEST_USER_NAME")
	if name == "" {
		name = "Alice"
	}

	collection, err := app.FindCollectionByNameOrId("users")
	if err != nil {
		app.Logger().Error("Failed to find users collection for seeding", "error", err)
		return
	}

	// Check if user already exists
	existing, _ := app.FindAuthRecordByEmail(collection, email)
	if existing != nil {
		app.Logger().Info("Test user already exists, skipping seed", "email", email)
		return
	}

	record := core.NewRecord(collection)
	record.SetEmail(email)
	record.Set("name", name)
	record.SetPassword("password123")
	record.SetVerified(true)

	if err := app.Save(record); err != nil {
		app.Logger().Error("Failed to seed test user", "error", err)
		return
	}

	app.Logger().Info("Seeded test user", "email", email, "name", name)
}
